INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1312, 183978, 5, 311, '我要离开', '下午2:00整从家里出发，半个小时后我出现在RUNNER教室里。结束了2个小时无聊的英语课后，我应约出现在人民体育场，在球场上漫无目的的奔跑。被球队长官干了几句，心里难免有些悲愤，但是我选择了沉默。回家草草地吃了盘炒饭，飞奔向学校，7:00整晚自习。刚进校门就看到我那位酷似kangta的同学，一起going to教室。得知一群死党同学正在csing，当然我和K奋不顾身的冲出校门，投入到我们的战队中。拼命撕杀了几回合，我决定离开那间充斥着烟草味道的房间。清晰的记得我换了25号机，打开winamp，一直重复着JAY的三首歌：半岛铁盒，回到过去，上海的1943。进了一个聊天室改名曰：听着半岛铁盒失恋中。竟有一个网友也附和起来，听着半兽人。有一句没一句的聊着。之后下线。
<br>　　回家的路有一段，我突然想了很多。高中的生活，不知不觉中，平凡而不平静地走完了三分之二。哭过、笑过、爱过、恨过，而这一切都随着时间默默地流逝，成为心底得，称之为回忆的东西，痛苦或快乐。 
<br>　　可以说高中生活就在我的沮丧、不屑以及不安中拉开了帷幕。 
<br>    对我而言，笑容是最有效的武器。半年的孤独心情，在同学们的笑容中灰飞湮灭，我又恢复了痞子本性，不再是那渴望阳光而又不敢触碰的吸血鬼，而是可以沐浴在和煦阳光中的人。
<br>    自习课上几个人窝着打七鬼五二三，代价是十分做五个俯卧撑。学习变得紧张时，我们依旧打牌、踢球、混日子。成绩忽上忽下，没关系，因为我笑得灿烂。我们吵过架，为踢球时假摔，为打牌时出老千，为无聊时的宣泄，为我们之间的友情。
<br>　　喜欢自言自语，至少这比与别人说话好得多。世界是一种不太需要理会得东西--对我而言。头发可以很长，直到自己觉得厌烦。至于其间老师的n次谆谆教诲，只不过是过耳微风，连左耳进右耳出的资格都没有。可以突然对某人说：“我爱你。”然后缠她好几天，最后告诉她：“你好恶心。”一直妄想着自己是痞子，总是极度的自傲与极度的自卑，极度的自恋着。妄想着成功，却躲进被子里等待成功。懒惰已经侵进了我的骨头。骂着别人的虚伪，却无耻的欺骗着世界。我盼着世人的关怀，却不削与他们靠近。 
<br>　　我悄悄的来到这了这个世界上，深刻的平凡着。 　　　　　　　　　　　　　　　 
<br>　　我平凡着，我可恶着，我永远做着小人物。经营我平凡，可我不差呀。可是我不愿意这么活着。　　
<br>　　我陷入了网络。可我还是平凡着…… 　　　　　　　　　　　　　　 
<br>　　不知道为什么我有理所当然放纵自己的理由。没有认真的奋斗过，总感觉一切都是飘飘然，都是那么虚幻和无所谓。开始有些颓废，以前对这个词总是嗤之以鼻，想自己不会到这种地步吧。但现在，慢慢的接近，却无力抵抗，更加的可怕。  
<br>　　离毕业越来越近。但却没什么感觉，日子总是那么平淡自然的过着。有时，很想多给自己的学生活留下点什么，那怕一点点，至少以后有回忆的空间，可一切都那么的平淡，生活真的是个空白。一直以来，都活在自己臆造的空间里，我讨厌世俗，客套，虚伪，理想的生活只有在我的心里。大学里，我努力开阔自己的视野，但看到了，很多东西让人失望，变得要客套要世俗要这一切才能活下去。我喜欢看书，喜欢书里的那份真实。我发现自己慢慢喜欢上了，那种有些颓废的小说，而且有些小资情调的，这些都很真实，其实人都很平凡，只是大家可意掩饰自己的弱点罢了。都说这个社会发展的有些极端，人们都变的那么自我，而夏天也流行暴露。可这些不都是压抑了很久的释放吗？很喜欢看别人开心的样子，时常被天真的笑所感染，那些都是发自内心的。  
<br>　　当与父母的关系日益紧张，我觉得累，他们也觉得累，我无法控制自己的行为，尽管知道那是什么下场。没日没夜的上网，看书，聊天，不做功课，与父亲对骂，与母亲无话可说。那段日子，不想用不堪回首，因为是我自己选择的，我不会说自己的坏话。它只是一个篇章，却时时出现在我的脑中，或许我已经很坚强，所以回忆的时候，总是显得从容。
<br>    一个暑假，我就在不断的不断的和键盘打着交道，渐渐丧失与人交谈的能力，拿起话筒时，简直就不知道该说些什么才好。做过一些傻事，衡量着自己在生和死的边界徘徊的脚步，我究竟能走多远，我究竟能走到哪儿，永远有多远，是否那是我一辈子都到不了的地方。                    
<br>　　爱情一直离我很远，看到别人爱的甜甜蜜蜜，死去活来，我想爱情是个奇妙的东西，有着更多的玄机。而涉足其中，你会迷失自我。很奇怪，我这个局外人，却在聊天时安慰了许多人，也许是我心太软，一直就希望大家都是开开心心，很多都是从书上搬来，不知不觉自己开始深沉的考虑问题，算是获益。我的那些朋友，如果知道，我是这样的角色，一定会笑起来。如果不是因为寂寞，我不会想起她，也许她永远是我心里最深埋的柔情，就算想起来了，我也会因为太自我而不承认。可是现在我寂寞了，所以我想她，我想有个人陪着我说说话，不管是谁……
<br>　　是啊，爱情也得把握。有很多人还在为自己的爱情苦苦的追寻，苦苦的等候，我淡淡的一笑，我还是我。我不乞求承诺，不依靠爱情，就我独自一人，是的，我独自一人，开始踏着破碎的脚步，追赶着永恒。多年以后，不知是否还会像少年时那样义无返顾，横冲直撞，或许不会了，经历多了，人也就平静了。当生活趋于平淡的时候，你所能做的就是静静地观望。   
<br>　　现在时间是22：53分，1小时53分钟完成了以上。我决定暂时离开了，一直以来，寂寞无聊是我的最大的借口，它分担了我的许多不开心、不快乐。本来还有很多关于这个网站要说，但是，是的。我掩饰悲伤。最后套用那个谁的话：“反正要回来，有啥舍不得。”', '下午2:00整从家里出发，半个小时后我出现在RUNNER教室里。结束了2个小时无聊的英语课后，我应约出现在人民体育场，在球场上漫无目的的奔跑。被球队长官干了几句，心里难免有些悲愤，但是我选择了沉默。回家草草地吃了盘炒饭，飞奔向学校，7:00整晚自习。刚进校门就看到我那位酷似kangta的同学，一起going to教室。得知一群死党同学正在csing，当然我和K奋不顾身的冲出校门，投入到我们的战队中。拼命撕杀了几回合，我决定离开那间充斥着烟草味道的房间。清晰的记得我换了25号机，打开winamp，一直重复着JAY的三首歌：半岛铁盒，回到过去，上海的1943。进了一个聊天室改名曰：听着半岛铁盒失恋中。竟有一个网友也附和起来，听着半兽人。有一句没一句的聊着。之后下线。

回家的路有一段，我突然想了很多。高中的生活，不知不觉中，平凡而不平静地走完了三分之二。哭过、笑过、爱过、恨过，而这一切都随着时间默默地流逝，成为心底得，称之为回忆的东西，痛苦或快乐。

可以说高中生活就在我的沮丧、不屑以及不安中拉开了帷幕。

对我而言，笑容是最有效的武器。半年的孤独心情，在同学们的笑容中灰飞湮灭，我又恢复了痞子本性，不再是那渴望阳光而又不敢触碰的吸血鬼，而是可以沐浴在和煦阳光中的人。

自习课上几个人窝着打七鬼五二三，代价是十分做五个俯卧撑。学习变得紧张时，我们依旧打牌、踢球、混日子。成绩忽上忽下，没关系，因为我笑得灿烂。我们吵过架，为踢球时假摔，为打牌时出老千，为无聊时的宣泄，为我们之间的友情。

喜欢自言自语，至少这比与别人说话好得多。世界是一种不太需要理会得东西--对我而言。头发可以很长，直到自己觉得厌烦。至于其间老师的n次谆谆教诲，只不过是过耳微风，连左耳进右耳出的资格都没有。可以突然对某人说：“我爱你。”然后缠她好几天，最后告诉她：“你好恶心。”一直妄想着自己是痞子，总是极度的自傲与极度的自卑，极度的自恋着。妄想着成功，却躲进被子里等待成功。懒惰已经侵进了我的骨头。骂着别人的虚伪，却无耻的欺骗着世界。我盼着世人的关怀，却不削与他们靠近。

我悄悄的来到这了这个世界上，深刻的平凡着。

我平凡着，我可恶着，我永远做着小人物。经营我平凡，可我不差呀。可是我不愿意这么活着。

我陷入了网络。可我还是平凡着……

不知道为什么我有理所当然放纵自己的理由。没有认真的奋斗过，总感觉一切都是飘飘然，都是那么虚幻和无所谓。开始有些颓废，以前对这个词总是嗤之以鼻，想自己不会到这种地步吧。但现在，慢慢的接近，却无力抵抗，更加的可怕。

离毕业越来越近。但却没什么感觉，日子总是那么平淡自然的过着。有时，很想多给自己的学生活留下点什么，那怕一点点，至少以后有回忆的空间，可一切都那么的平淡，生活真的是个空白。一直以来，都活在自己臆造的空间里，我讨厌世俗，客套，虚伪，理想的生活只有在我的心里。大学里，我努力开阔自己的视野，但看到了，很多东西让人失望，变得要客套要世俗要这一切才能活下去。我喜欢看书，喜欢书里的那份真实。我发现自己慢慢喜欢上了，那种有些颓废的小说，而且有些小资情调的，这些都很真实，其实人都很平凡，只是大家可意掩饰自己的弱点罢了。都说这个社会发展的有些极端，人们都变的那么自我，而夏天也流行暴露。可这些不都是压抑了很久的释放吗？很喜欢看别人开心的样子，时常被天真的笑所感染，那些都是发自内心的。

当与父母的关系日益紧张，我觉得累，他们也觉得累，我无法控制自己的行为，尽管知道那是什么下场。没日没夜的上网，看书，聊天，不做功课，与父亲对骂，与母亲无话可说。那段日子，不想用不堪回首，因为是我自己选择的，我不会说自己的坏话。它只是一个篇章，却时时出现在我的脑中，或许我已经很坚强，所以回忆的时候，总是显得从容。

一个暑假，我就在不断的不断的和键盘打着交道，渐渐丧失与人交谈的能力，拿起话筒时，简直就不知道该说些什么才好。做过一些傻事，衡量着自己在生和死的边界徘徊的脚步，我究竟能走多远，我究竟能走到哪儿，永远有多远，是否那是我一辈子都到不了的地方。

爱情一直离我很远，看到别人爱的甜甜蜜蜜，死去活来，我想爱情是个奇妙的东西，有着更多的玄机。而涉足其中，你会迷失自我。很奇怪，我这个局外人，却在聊天时安慰了许多人，也许是我心太软，一直就希望大家都是开开心心，很多都是从书上搬来，不知不觉自己开始深沉的考虑问题，算是获益。我的那些朋友，如果知道，我是这样的角色，一定会笑起来。如果不是因为寂寞，我不会想起她，也许她永远是我心里最深埋的柔情，就算想起来了，我也会因为太自我而不承认。可是现在我寂寞了，所以我想她，我想有个人陪着我说说话，不管是谁……

是啊，爱情也得把握。有很多人还在为自己的爱情苦苦的追寻，苦苦的等候，我淡淡的一笑，我还是我。我不乞求承诺，不依靠爱情，就我独自一人，是的，我独自一人，开始踏着破碎的脚步，追赶着永恒。多年以后，不知是否还会像少年时那样义无返顾，横冲直撞，或许不会了，经历多了，人也就平静了。当生活趋于平淡的时候，你所能做的就是静静地观望。

现在时间是22：53分，1小时53分钟完成了以上。我决定暂时离开了，一直以来，寂寞无聊是我的最大的借口，它分担了我的许多不开心、不快乐。本来还有很多关于这个网站要说，但是，是的。我掩饰悲伤。最后套用那个谁的话：“反正要回来，有啥舍不得。”', '三年的时间不知不觉中在指间流逝,本以为会有许多知心朋友,但今天才真正发觉我用真心和诚意换回的都是些伪善的迎合.说起来真是酸酸的.晴说过在许多时候,人都是很表面化的,很冷漠事态的一种动物,但当时我认为只有她会说出那样的话来,而今天我明白了她所说的真正含义.......', '2002-09-22 23:07:00', 16, '20030112223418_bbsid_183978_board_5_ff01443199.html', '20030112223418');
